static final Map<String, String?> _businessKeyCache = {};

static Future<String?> getBusinessUniqueKeyRaw(String schemaName) async {
  if (kIsWeb) return null;

  // ⚡ Check RAM cache first - instant return!
  if (_businessKeyCache.containsKey(schemaName)) {
    return _businessKeyCache[schemaName];
  }

  final db = await _database;
  await initConfigurationsTable();
  final results = db.select('SELECT business_unique_key FROM "schema_configurations" WHERE schema_name = ?', [schemaName]);

  if (results.isNotEmpty) {
    final val = results.first['business_unique_key'] as String?;
    _businessKeyCache[schemaName] = val; // Warm up cache
    return val;
  }

  _businessKeyCache[schemaName] = null; // Store negative hit
  return null;
}
```

